JS_CODE = 'const questions = [\n    {\n      id: \'type\',\n      text: \'独立の形態を教えてください\',\n      options: [\'個人事業主（フリーランス）\', \'株式会社を設立\', \'合同会社（LLC）を設立\', \'まだ決めていない\']\n    },\n    {\n      id: \'industry\',\n      text: \'業種・仕事の種類を教えてください\',\n      options: [\'IT・Web・デザイン\', \'コンサル・士業・講師\', \'飲食・小売・実店舗\', \'製造・建設・技術職\', \'その他サービス業\']\n    },\n    {\n      id: \'office\',\n      text: \'事務所・オフィスの予定はありますか？\',\n      options: [\'自宅で作業（オフィス不要）\', \'コワーキングスペースを利用\', \'賃貸オフィスを借りる予定\', \'テナント・店舗を借りる予定\']\n    },\n    {\n      id: \'equipment\',\n      text: \'開業に必要な設備・機材はどのくらいですか？\',\n      options: [\'PC・スマホのみ（10万円未満）\', \'機材・備品で50万円未満\', \'設備投資で50〜200万円\', \'大型設備で200万円以上\']\n    },\n    {\n      id: \'savings\',\n      text: \'独立時に用意できる自己資金はどのくらいですか？\',\n      options: [\'50万円未満\', \'50〜100万円\', \'100〜300万円\', \'300万円以上\']\n    },\n    {\n      id: \'revenue\',\n      text: \'独立後1年目に期待する月間売上目標はいくらですか？\',\n      options: [\'30万円未満\', \'30〜60万円\', \'60〜100万円\', \'100〜200万円\', \'200万円以上\']\n    },\n    {\n      id: \'tax_knowledge\',\n      text: \'確定申告・経理の知識はありますか？\',\n      options: [\'全くない\', \'少しある（青色申告は知っている）\', \'ある程度できる\', \'プロに任せる予定\']\n    }\n  ];\n\n  let currentStep = 0;\n  let answers = {};\n\n  function renderQuestion() {\n    const q = questions[currentStep];\n    document.getElementById(\'step-label\').textContent = `質問 ${currentStep + 1} / ${questions.length}`;\n    document.getElementById(\'progress-bar\').style.width = `${((currentStep + 1) / questions.length) * 100}%`;\n    document.getElementById(\'prev-btn\').classList.toggle(\'hidden\', currentStep === 0);\n    document.getElementById(\'next-btn\').textContent = currentStep === questions.length - 1 ? \'診断する\' : \'次へ\';\n\n    let html = `<p class="font-semibold text-gray-800 mb-4">${q.text}</p><div class="space-y-2">`;\n    q.options.forEach(opt => {\n      const checked = answers[q.id] === opt ? \'checked\' : \'\';\n      html += `<label class="flex items-center gap-3 p-3 border border-gray-200 rounded-xl cursor-pointer hover:border-emerald-400 transition has-[:checked]:border-emerald-500 has-[:checked]:bg-emerald-50">\n        <input type="radio" name="${q.id}" value="${opt}" ${checked} class="accent-emerald-600"> <span class="text-sm">${opt}</span>\n      </label>`;\n    });\n    html += \'</div>\';\n    document.getElementById(\'question-area\').innerHTML = html;\n  }\n\n  function saveAnswer() {\n    const el = document.querySelector(`input[name="${questions[currentStep].id}"]:checked`);\n    if (!el) { alert(\'選択してください\'); return false; }\n    answers[questions[currentStep].id] = el.value;\n    return true;\n  }\n\n  function nextStep() {\n    if (!saveAnswer()) return;\n    if (currentStep < questions.length - 1) { currentStep++; renderQuestion(); }\n    else showResult();\n  }\n\n  function prevStep() {\n    if (currentStep > 0) { currentStep--; renderQuestion(); }\n  }\n\n  function calcCosts() {\n    let initialCost = 0;\n    let monthlyCost = 0;\n\n    // 法人設立費用\n    if (answers.type === \'株式会社を設立\') { initialCost += 25; monthlyCost += 3; }\n    else if (answers.type === \'合同会社（LLC）を設立\') { initialCost += 10; monthlyCost += 2; }\n\n    // 業種別\n    if (answers.industry === \'飲食・小売・実店舗\') { initialCost += 150; monthlyCost += 30; }\n    else if (answers.industry === \'製造・建設・技術職\') { initialCost += 80; monthlyCost += 15; }\n    else { initialCost += 20; monthlyCost += 5; }\n\n    // オフィス\n    if (answers.office === \'賃貸オフィスを借りる予定\') { initialCost += 40; monthlyCost += 15; }\n    else if (answers.office === \'テナント・店舗を借りる予定\') { initialCost += 100; monthlyCost += 40; }\n    else if (answers.office === \'コワーキングスペースを利用\') { monthlyCost += 3; }\n\n    // 設備\n    if (answers.equipment === \'機材・備品で50万円未満\') initialCost += 30;\n    else if (answers.equipment === \'設備投資で50〜200万円\') initialCost += 100;\n    else if (answers.equipment === \'大型設備で200万円以上\') initialCost += 250;\n\n    // 月間固定費（社会保険・通信等）\n    monthlyCost += 5; // 国民健康保険・年金の基本分\n\n    return { initialCost, monthlyCost };\n  }\n\n  function showResult() {\n    document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n    document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n    const { initialCost, monthlyCost } = calcCo'
